import boto3
from botocore.exceptions import ClientError
import sys

def list_s3_files():
    """
    Lists all files in an S3 bucket using secure credential management.
    
    SECURITY NOTE: This script requires proper AWS credentials configuration.
    Never hardcode credentials in source code.
    """
    
    # SECURITY: Do NOT hardcode credentials
    # Use one of these secure methods instead:
    # 1. AWS CLI configuration (~/.aws/credentials)
    # 2. Environment variables (AWS_ACCESS_KEY_ID, AWS_SECRET_ACCESS_KEY)
    # 3. IAM roles (recommended for EC2/Lambda)
    # 4. AWS SSO
    
    bucket_name = 'demo-bucket'
    
    try:
        # Create S3 client using default credential chain
        # This will automatically use credentials from:
        # - Environment variables
        # - AWS credentials file
        # - IAM role (if running on AWS)
        s3_client = boto3.client('s3')
        
        print(f"Connecting to bucket: {bucket_name}")
        print("-" * 50)
        
        # List objects in the bucket
        response = s3_client.list_objects_v2(Bucket=bucket_name)
        
        if 'Contents' in response:
            print(f"Files in {bucket_name}:")
            for obj in response['Contents']:
                print(f"  - {obj['Key']} (Size: {obj['Size']} bytes)")
            print(f"\nTotal files: {len(response['Contents'])}")
        else:
            print(f"No files found in {bucket_name}")
            
    except ClientError as e:
        error_code = e.response['Error']['Code']
        if error_code == 'NoSuchBucket':
            print(f"Error: Bucket '{bucket_name}' does not exist")
        elif error_code == 'AccessDenied':
            print("Error: Access denied. Please check your AWS credentials and permissions")
        else:
            print(f"AWS Error: {e}")
        sys.exit(1)
    except Exception as e:
        print(f"Error: {e}")
        sys.exit(1)

